function stockAvailability(arr)
{
  return new Promise((resolve,reject)=>
  {
    setTimeout(()=>
    {
      for(let obj of arr)
      {

        if(obj.available === 0 || obj.available == null || obj.requested == null)
        {
          reject("Rejected");
          return;
        }

        if(obj.available < obj.requested)
        {
          resolve("Partial");
          return;
        }


      }
      resolve("Available");

    },1000);

  });

}

stockAvailability([
  {item: 'Shirts', requested: 10, available: 5 },
  {item: 'Jeans', requested: 6, available: 6 }
])
.then(res=>console.log(res))
.catch(err=>console.log(err));